<?php

namespace App\Http\Controllers;

use App\Models\Job;
use Illuminate\Http\Request;

class JobController extends Controller
{
    public function index(Request $request)
    {
        $query = Job::where('status', 'published') ->with('company'); if ($request->filled('search')) { $search = $request->search; $query->where(function($q) use ($search) { $q->where('title', 'like', "%{$search}%") ->orWhere('description', 'like', "%{$search}%") ->orWhere('location', 'like', "%{$search}%") ->orWhere('experience', 'like', "%{$search}%") ->orWhere('experience_level', 'like', "%{$search}%") ->orWhere('type', 'like', "%{$search}%") ->orWhere('work_type', 'like', "%{$search}%") ->orWhereHas('company', function($companyQuery) use ($search) { $companyQuery->where('name', 'like', "%{$search}%") ->orWhere('industry', 'like', "%{$search}%"); }); }); } if ($request->filled('company')) { $query->where('company_id', $request->company); } if ($request->filled('location')) { $query->where('location', 'like', "%{$request->location}%"); } if ($request->filled('type')) { $query->where('type', $request->type); } if ($request->filled('work_type')) { $query->where('work_type', $request->work_type); } if ($request->filled('category')) { $query->whereJsonContains('tags', $request->category); } if ($request->filled('experience')) { $query->where(function($q) use ($request) { $q->where('experience_level', 'like', "%{$request->experience}%") ->orWhere('experience', 'like', "%{$request->experience}%"); }); } if ($request->filled('salary_min')) { $query->where('salary_min', '>=', $request->salary_min); } if ($request->filled('salary_max')) { $query->where('salary_max', '<=', $request->salary_max); } $sort = $request->get('sort', 'newest'); switch ($sort) { case 'salary_asc': $query->orderBy('salary_min', 'asc'); break; case 'salary_desc': $query->orderBy('salary_max', 'desc'); break; case 'title': $query->orderBy('title', 'asc'); break; case 'newest': default: $query->orderBy('created_at', 'desc'); break; } if ($request->ajax() || $request->has('page')) { $page = $request->get('page', 2); $perPage = 5; $offset = ($page - 2) * $perPage + 10; $jobs = $query->skip($offset)->take($perPage)->get(); $totalJobs = $query->count(); $hasMore = ($offset + $perPage) < $totalJobs; return api_json([ 'html' => view('jobs.partials.job-card', ['jobs' => $jobs])->render(), 'hasMore' => $hasMore, 'nextPage' => $page + 1 ]); } $tab = $request->get('tab', 'all'); $locations = Job::where('status', 'published') ->whereNotNull('location') ->distinct() ->pluck('location') ->sort() ->values(); $categories = Job::where('status', 'published') ->whereNotNull('tags') ->get() ->pluck('tags') ->flatten() ->unique() ->values() ->sort() ->values(); if ($categories->isEmpty()) { $categories = collect(['Design', 'Développement', 'Informatique', 'Marketing', 'Finance', 'Ventes', 'Ressources Humaines', 'Support']); } $types = Job::where('status', 'published') ->whereNotNull('type') ->distinct() ->pluck('type') ->sort() ->values(); if ($types->isEmpty()) { $types = collect(['CDI', 'CDD', 'Stage', 'Freelance', 'Alternance']); } $jobs = $query->paginate(10); $totalPublishedJobs = Job::where('status', 'published')->count(); return view('jobs.index', compact('jobs', 'totalPublishedJobs', 'tab', 'locations', 'categories', 'types'));
    }

    public function show(Job $job)
    {
        $job->load('company'); $job->incrementViews(); $relatedJobs = collect(); $sameCompanyJobs = Job::where('status', 'published') ->where('company_id', $job->company_id) ->where('id', '!=', $job->id) ->with('company') ->limit(2) ->get(); $relatedJobs = $relatedJobs->merge($sameCompanyJobs); if ($relatedJobs->count() < 3) { $sameTypeJobs = Job::where('status', 'published') ->where('type', $job->type) ->where('id', '!=', $job->id) ->whereNotIn('id', $relatedJobs->pluck('id')) ->with('company') ->limit(3 - $relatedJobs->count()) ->get(); $relatedJobs = $relatedJobs->merge($sameTypeJobs); } if ($relatedJobs->count() < 3) { $location = explode(',', $job->location)[0]; $similarLocationJobs = Job::where('status', 'published') ->where('location', 'like', '%' . $location . '%') ->where('id', '!=', $job->id) ->whereNotIn('id', $relatedJobs->pluck('id')) ->with('company') ->limit(3 - $relatedJobs->count()) ->get(); $relatedJobs = $relatedJobs->merge($similarLocationJobs); } if ($relatedJobs->count() < 3) { $otherJobs = Job::where('status', 'published') ->where('id', '!=', $job->id) ->whereNotIn('id', $relatedJobs->pluck('id')) ->with('company') ->limit(3 - $relatedJobs->count()) ->get(); $relatedJobs = $relatedJobs->merge($otherJobs); } $relatedJobs = $relatedJobs->take(3); $recentJobs = Job::where('status', 'published') ->where('id', '!=', $job->id) ->latest() ->with('company') ->limit(4) ->get(); $existingApplication = null; if (auth()->check() && auth()->user()->isCandidate()) { $existingApplication = \App\Models\Application::where('job_id', $job->id) ->where('candidate_id', auth()->id()) ->first(); } return view('jobs.show', compact('job', 'relatedJobs', 'existingApplication', 'recentJobs'));
    }

    public function searchApi(Request $request)
    {
        $search = $request->get('q'); if (empty($search)) { return api_json(['jobs' => []]); } $jobs = Job::where('status', 'published') ->where(function($q) use ($search) { $q->where('title', 'like', "%{$search}%") ->orWhereHas('company', function($companyQuery) use ($search) { $companyQuery->where('name', 'like', "%{$search}%"); }); }) ->with('company') ->limit(6) ->get() ->map(function($job) { return [ 'id' => $job->id, 'title' => $job->title, 'company_name' => $job->company ? $job->company->name : 'N/A', 'slug' => $job->slug, 'url' => route('jobs.show', $job->slug), ]; }); return api_json(['jobs' => $jobs]);
    }
}